class CounterThread extends Thread {
    String threadName;
    int count;

    CounterThread(String threadName, int count) {
        this.threadName = threadName;
        this.count = count;
    }

    @Override
    public void run() {
        for (int i = 1; i <= count; i++) {
            System.out.println(threadName + " - Step " + i);
        }
    }
}

public class ThreadDemo {
    public static void main(String[] args) {
        CounterThread t1 = new CounterThread("Thread-A", 3);
        CounterThread t2 = new CounterThread("Thread-B", 3);

        t1.start();
        t2.start();
    }
}

class PrintTask implements Runnable {
    String message;
    int times;

    PrintTask(String message, int times) {
        this.message = message;
        this.times = times;
    }

    @Override
    public void run() {
        for (int i = 0; i < times; i++) {
            System.out.println(message);
        }
    }
}

public class RunnableDemo {
    public static void main(String[] args) throws InterruptedException {
        Runnable task1 = new PrintTask("Hello from Task 1", 2);
        Runnable task2 = new PrintTask("Hello from Task 2", 2);

        Thread t1 = new Thread(task1);
        Thread t2 = new Thread(task2);

        t1.start();
        t1.join(); // wait for t1 to finish before starting t2
        t2.start();
        t2.join();

        System.out.println("Both tasks done.");
    }
}

class SharedCounter {
    private int count = 0;

    // Synchronized method: only one thread can execute this at a time
    public synchronized void increment() {
        count++;
    }

    public int getCount() {
        return count;
    }
}

public class SyncDemo {
    public static void main(String[] args) throws InterruptedException {
        SharedCounter counter = new SharedCounter();

        Runnable task = () -> {
            for (int i = 0; i < 1000; i++) {
                counter.increment();
            }
        };

        Thread t1 = new Thread(task);
        Thread t2 = new Thread(task);

        t1.start();
        t2.start();
        t1.join();
        t2.join();

        System.out.println("Final count: " + counter.getCount());
    }
}
